const crypto = require('crypto');

class Block {
  constructor(index, previousHash, timestamp, data) {
    this.index = index;
    this.previousHash = previousHash;
    this.timestamp = timestamp;
    this.data = data;
    this.hash = this.calculateHash();
  }

  calculateHash() {
    const dataString = `${this.index}${this.previousHash}${this.timestamp}${this.data}`;
    return crypto.createHash('sha256').update(dataString).digest('hex');
  }
}

class Blockchain {
  constructor() {
    this.chain = [this.createGenesisBlock()];
  }

  createGenesisBlock() {
    return new Block(0, '0', Date.now(), 'Genesis Block');
  }

  getLatestBlock() {
    return this.chain[this.chain.length - 1];
  }

  addBlock(newBlock) {
    newBlock.previousHash = this.getLatestBlock().hash;
    newBlock.hash = newBlock.calculateHash();
    this.chain.push(newBlock);
  }

  mineBlock(data) {
    const newBlock = new Block(this.chain.length, this.getLatestBlock().hash, Date.now(), data);
    this.addBlock(newBlock);
  }
}

// Example usage:
const blockchain = new Blockchain();
blockchain.mineBlock('Transaction 1');
blockchain.mineBlock('Transaction 2');
```
